from abc import ABC, abstractmethod

# Abstract base class
class Shape(ABC):
    def __init__(self, color='black'):
        self.color = color

    @abstractmethod
    def area(self) -> float: ...

    @abstractmethod
    def perimeter(self) -> float: ...

    def describe(self):
        return f'{self.color} {type(self).__name__}: area={self.area():.2f}'

class Circle(Shape):
    def __init__(self, radius, color='black'):
        super().__init__(color)  # call parent __init__
        self.radius = radius

    def area(self):
        import math
        return math.pi * self.radius ** 2

    def perimeter(self):
        import math
        return 2 * math.pi * self.radius

# Multiple inheritance
class Flyable:
    def fly(self): return 'Flying!'

class Swimmable:
    def swim(self): return 'Swimming!'

class Duck(Flyable, Swimmable):
    pass

duck = Duck()
duck.fly()   # 'Flying!'
duck.swim()  # 'Swimming!'

# MRO: Method Resolution Order
print(Duck.__mro__)
# (<class 'Duck'>, <class 'Flyable'>, <class 'Swimmable'>, <class 'object'>)

# Diamond problem: super() follows MRO correctly
class A:
    def greet(self): return 'A'

class B(A):
    def greet(self): return 'B->' + super().greet()

class C(A):
    def greet(self): return 'C->' + super().greet()

class D(B, C):
    def greet(self): return 'D->' + super().greet()

print(D().greet())  # D->B->C->A  (follows MRO, not just parent chain)

